"use client";

import React from 'react';
import { Search, PlusCircle } from 'lucide-react';
import { User as UserType } from '../types';

// Modular Sub-components
import SimulatorControls from './header/SimulatorControls';
import DesktopNavbar from './header/DesktopNavbar';
import UserProfileIndicator from './header/UserProfileIndicator';

interface HeaderProps {
  currentUser: UserType;
  activeTab: string;
  setActiveTab: (tab: string) => void;
  openCreatePost: () => void;
  unreadMessagesCount: number;
  onLogoutSimulate: () => void;
  isMobileSimulated: boolean;
  setIsMobileSimulated: (val: boolean) => void;
  searchTerm: string;
  setSearchTerm: (val: string) => void;
}

export default function Header({
  currentUser,
  activeTab,
  setActiveTab,
  openCreatePost,
  unreadMessagesCount,
  onLogoutSimulate,
  isMobileSimulated,
  setIsMobileSimulated,
  searchTerm,
  setSearchTerm
}: HeaderProps) {
  return (
    <header className="sticky top-0 z-40 w-full bg-[#121214]/90 backdrop-blur-md border-b border-[#242428] shadow-md select-none font-sans">
      {/* Top Banner with Device Simulator togglers & Community Tagline */}
      <div className="bg-[#09090b] text-zinc-400 text-xs py-1.5 px-4 flex justify-between items-center select-none font-mono border-b border-[#1c1c1e]">
        <div className="flex items-center gap-1.5">
          <span className="w-2 h-2 rounded-full bg-[#FF3F3F]" />
          <span className="text-[11px] tracking-wide text-zinc-300">HuntInTown • Real-time verified local response network</span>
        </div>
        
        {/* Device Simulator togglers */}
        <SimulatorControls 
          isMobileSimulated={isMobileSimulated} 
          setIsMobileSimulated={setIsMobileSimulated} 
        />
      </div>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex items-center justify-between h-16">
          {/* Logo Brand */}
          <div className="flex items-center gap-2 cursor-pointer" onClick={() => setActiveTab('landing')}>
            <div className="text-[#FF3F3F] font-black text-xl tracking-tighter uppercase font-display select-none flex items-center gap-1.5">
              <span className="w-8 h-8 rounded-lg bg-[#FF3F3F] text-white font-black text-lg flex items-center justify-center font-display">R</span>
              <span>HuntInTown</span>
            </div>
          </div>

          {/* Search bar inside header (for larger displays) */}
          <div className="hidden md:flex flex-1 max-w-sm mx-6">
            <div className="relative w-full">
              <span className="absolute inset-y-0 left-0 flex items-center pl-3 pointer-events-none text-zinc-550">
                <Search className="h-4 w-4" />
              </span>
              <input
                id="header-search-input"
                type="text"
                placeholder="Search sofas, math tuition, local contractors..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full pl-9 pr-4 py-1.5 text-xs bg-[#1a1a1e] border border-[#2d2d34] text-zinc-100 rounded-lg placeholder-zinc-550 focus:outline-[#FF3F3F]/30 focus:border-[#FF3F3F] focus:bg-[#202025] transition"
              />
            </div>
          </div>

          {/* Desktop Navigation Linkages (Modular Component) */}
          <DesktopNavbar 
            activeTab={activeTab} 
            setActiveTab={setActiveTab} 
            unreadMessagesCount={unreadMessagesCount} 
          />

          {/* Action Button & Active User Indicator */}
          <div className="flex items-center gap-3">
            <button
              id="header-create-post-btn"
              onClick={openCreatePost}
              className="hidden sm:flex items-center gap-1.5 px-3.5 py-1.5 text-xs font-black bg-[#FF3F3F] hover:bg-[#E53535] text-white rounded-lg transition cursor-pointer font-display tracking-widest uppercase"
            >
              <PlusCircle className="w-3.5 h-3.5" />
              <span>Post Need</span>
            </button>

            {/* Simulated Live User Profile Indicator (Modular Component) */}
            <UserProfileIndicator 
              currentUser={currentUser} 
              setActiveTab={setActiveTab} 
              onLogoutSimulate={onLogoutSimulate} 
            />
          </div>
        </div>
      </div>
    </header>
  );
}
