"use client";

import { useState, FormEvent } from 'react';
import { Post, User } from '../types';
import { FUNCTIONAL_CATEGORIES } from '../data';
import { X, CalendarRange } from 'lucide-react';

// Modular Component Imports
import CustomQuestionsInput from './create-post/CustomQuestionsInput';
import ContactMethodsToggle from './create-post/ContactMethodsToggle';
import ImageUploadArea from './create-post/ImageUploadArea';

interface CreatePostProps {
  currentUser: User;
  onClose: () => void;
  onSubmit: (newPost: Omit<Post, 'id' | 'createdAt' | 'author' | 'comments' | 'offersCount'>) => void;
}

export default function CreatePost({ currentUser, onClose, onSubmit }: CreatePostProps) {
  const [description, setDescription] = useState('');
  const [category, setCategory] = useState('Home & Living');
  const [budget, setBudget] = useState('₹15,000');
  const [timeline, setTimeline] = useState('5 Days');
  const [location, setLocation] = useState(currentUser.location || 'Noida, Sector 62');
  const [expiryDays, setExpiryDays] = useState(10);
  const [questions, setQuestions] = useState<string[]>(['']);
  
  // Contact Method states
  const [contactMethods, setContactMethods] = useState({
    whatsApp: true,
    phone: true,
    chat: true
  });

  const handleSubmit = (e: FormEvent) => {
    e.preventDefault();
    if (!description.trim()) return;

    // Generate a title automatically from the first few words or description
    const titleVal = description.length > 35 
      ? description.substring(0, 35) + '...' 
      : description;

    const expiryDate = new Date();
    expiryDate.setDate(expiryDate.getDate() + expiryDays);

    const filteredQuestions = questions
      .map(q => q.trim())
      .filter(q => q.length > 0);

    onSubmit({
      title: titleVal,
      description,
      category,
      location,
      type: 'help_needed',
      budget: budget || 'Negotiable',
      status: 'open',
      expiryDays,
      expiresAt: expiryDate.toISOString(),
      questions: filteredQuestions
    });
  };

  return (
    <div className="fixed inset-0 z-50 bg-black/80 backdrop-blur-md flex items-center justify-center p-4 overflow-y-auto">
      <div className="bg-[#121214] rounded-2xl border border-[#232327] max-w-md w-full max-h-[92vh] flex flex-col overflow-hidden text-zinc-100 shadow-2xl animate-in zoom-in-95 duration-200">
        
        {/* Header Visual */}
        <div className="p-4 border-b border-[#1e1e21] flex justify-between items-center bg-[#17171a] select-none">
          <span className="text-xs font-black tracking-widest uppercase text-zinc-300 font-mono">Post Requirement</span>
          <button
            id="close-post-modal-btn"
            onClick={onClose}
            className="p-1 rounded-full text-zinc-400 hover:text-white hover:bg-zinc-800 transition cursor-pointer"
          >
            <X className="w-5 h-5" />
          </button>
        </div>

        {/* Form Body */}
        <form onSubmit={handleSubmit} className="p-5 overflow-y-auto flex-1 space-y-4 font-sans text-left">
          
          {/* Requirement Description */}
          <div>
            <label className="block text-[10px] uppercase font-bold tracking-wider text-zinc-400 mb-1">What do you need?</label>
            <textarea
              id="create-post-desc-textarea"
              placeholder="Describe your requirement in detail..."
              rows={4}
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              required
              maxLength={300}
              className="w-full text-xs px-3.5 py-2.5 bg-[#0b0b0c] border border-[#232327] text-zinc-100 rounded-lg placeholder-zinc-650 focus:outline-hidden focus:border-[#FF3F3F] transition resize-none font-sans"
            />
            <div className="text-right text-[9px] text-zinc-550 mt-0.5 font-mono">
              {description.length}/300
            </div>
          </div>

          {/* Category Dropdown */}
          <div>
            <label className="block text-[10px] uppercase font-bold tracking-wider text-zinc-400 mb-1">Category</label>
            <select
              id="create-post-category-select"
              value={category}
              onChange={(e) => setCategory(e.target.value)}
              className="w-full text-xs px-3.5 py-2.5 bg-[#0b0b0c] border border-[#232327] text-zinc-100 rounded-lg focus:outline-[#FF3F3F]/30 focus:border-[#FF3F3F] transition cursor-pointer"
            >
              {FUNCTIONAL_CATEGORIES.filter(c => c !== 'All Categories').map(cat => (
                <option key={cat} value={cat} className="bg-[#121214]">{cat}</option>
              ))}
            </select>
          </div>

          {/* Budget & Timeline */}
          <div className="grid grid-cols-2 gap-3">
            <div>
              <label className="block text-[10px] uppercase font-bold tracking-wider text-zinc-400 mb-1">Budget</label>
              <input
                id="create-post-budget"
                type="text"
                placeholder="Enter budget (e.g. ₹15,000)"
                value={budget}
                onChange={(e) => setBudget(e.target.value)}
                className="w-full text-xs px-3 py-2 bg-[#0b0b0c] border border-[#232327] text-zinc-100 rounded-lg placeholder-zinc-600 focus:outline-hidden focus:border-[#FF3F3F]"
              />
            </div>
            <div>
              <label className="block text-[10px] uppercase font-bold tracking-wider text-zinc-400 mb-1">Timeline</label>
              <input
                id="create-post-timeline"
                type="text"
                placeholder="e.g. 5 Days, Long Term"
                value={timeline}
                onChange={(e) => setTimeline(e.target.value)}
                className="w-full text-xs px-3 py-2 bg-[#0b0b0c] border border-[#232327] text-zinc-100 rounded-lg placeholder-zinc-650 focus:outline-hidden focus:border-[#FF3F3F]"
              />
            </div>
          </div>

          {/* Location Coordinate */}
          <div>
            <label className="block text-[10px] uppercase font-bold tracking-wider text-zinc-400 mb-1">Location</label>
            <input
              id="create-post-location-input"
              type="text"
              placeholder="Select your location (e.g. Noida, Sector 62)"
              value={location}
              onChange={(e) => setLocation(e.target.value)}
              className="w-full text-xs px-3.5 py-2.5 bg-[#0b0b0c] border border-[#232327] text-zinc-100 rounded-lg placeholder-zinc-650 focus:outline-hidden focus:border-[#FF3F3F]"
            />
          </div>

          {/* Automatic Expiration Timeline */}
          <div>
            <label className="block text-[10px] uppercase font-bold tracking-wider text-zinc-400 mb-1 flex items-center gap-1.5 font-mono">
              <CalendarRange className="w-3.5 h-3.5 text-[#FF3F3F]" />
              <span>Automatically Expire Post After</span>
            </label>
            <select
              id="create-post-expiry-select"
              value={expiryDays}
              onChange={(e) => setExpiryDays(Number(e.target.value))}
              className="w-full text-xs px-3.5 py-2.5 bg-[#0b0b0c] border border-[#232327] text-zinc-100 rounded-lg focus:outline-[#FF3F3F]/30 focus:border-[#FF3F3F] transition cursor-pointer"
            >
              <option value={1} className="bg-[#121214]">1 Day (Urgent Rush)</option>
              <option value={2} className="bg-[#121214]">2 Days</option>
              <option value={3} className="bg-[#121214]">3 Days</option>
              <option value={5} className="bg-[#121214]">5 Days</option>
              <option value={7} className="bg-[#121214]">7 Days</option>
              <option value={10} className="bg-[#121214]">10 Days (Maximum Duration)</option>
            </select>
            <p className="text-[9px] text-zinc-500 mt-1">This listing will automatically withdraw and show as Expired after your chosen period.</p>
          </div>

          {/* Custom Questions for Responses (Modular Component) */}
          <CustomQuestionsInput questions={questions} setQuestions={setQuestions} />

          {/* Add Images (Modular Component) */}
          <ImageUploadArea />

          {/* Contact Methods Toggle (Modular Component) */}
          <ContactMethodsToggle contactMethods={contactMethods} setContactMethods={setContactMethods} />

          {/* Submission and Close buttons */}
          <div className="pt-4 flex flex-col gap-2 font-display">
            <button
              id="submit-create-post-btn"
              type="submit"
              className="w-full py-2.5 bg-[#FF3F3F] hover:bg-[#E53535] text-white font-black rounded-lg transition text-xs tracking-widest uppercase cursor-pointer"
            >
              Post Requirement
            </button>
            <button
              id="cancel-create-post-btn"
              type="button"
              onClick={onClose}
              className="w-full py-2 text-zinc-400 hover:text-white text-[10px] hover:bg-zinc-800 rounded transition cursor-pointer font-black bg-transparent uppercase tracking-wider"
            >
              Cancel Formulation
            </button>
          </div>

        </form>
      </div>
    </div>
  );
}
