"use client";

import React, { ReactNode } from 'react';
import { AppContextProvider, useAppContext } from '../context/AppContext';
import Header from '../components/Header';
import CreatePost from '../components/CreatePost';
import LoginModal from '../components/LoginModal';
import { Home, LayoutGrid, Plus, MessageSquare, User as UserIcon } from 'lucide-react';
import '../index.css';

function RootLayoutContent({ children }: { children: ReactNode }) {
  const {
    currentUser,
    activeTab,
    setActiveTab,
    isCreatePostOpen,
    setIsCreatePostOpen,
    isLoginOpen,
    setIsLoginOpen,
    isMobileSimulated,
    setIsMobileSimulated,
    unreadMessagesCount,
    handleLoginSimulate,
    handleLogoutSimulate,
    handleCreatePost,
    searchTerm,
    setSearchTerm,
  } = useAppContext();

  return (
    <div className="absolute inset-0 bg-[#09090b] flex flex-col antialiased select-text text-zinc-100 overflow-x-hidden font-sans">
      {!isMobileSimulated ? (
        <div className="flex-1 flex flex-col min-h-screen">
          <Header 
            currentUser={currentUser}
            activeTab={activeTab}
            setActiveTab={setActiveTab}
            openCreatePost={() => setIsCreatePostOpen(true)}
            unreadMessagesCount={unreadMessagesCount}
            onLogoutSimulate={handleLogoutSimulate}
            isMobileSimulated={isMobileSimulated}
            setIsMobileSimulated={setIsMobileSimulated}
            searchTerm={searchTerm}
            setSearchTerm={setSearchTerm}
          />
          
          <main className="flex-1 max-w-7xl w-full mx-auto px-4 sm:px-6 lg:px-8 py-6 pb-20 md:pb-8">
            {children}
          </main>
          
          {/* Universal Mobile Bottom Bar themed for HuntInTown */}
          <div className="lg:hidden fixed bottom-0 inset-x-0 bg-[#121214] border-t border-[#232327] flex items-center justify-around py-2.5 z-40 shadow-xl">
            <button 
              id="mobile-bottom-nav-home"
              onClick={() => setActiveTab('landing')}
              className={`flex flex-col items-center p-1 text-center font-bold cursor-pointer transition ${
                activeTab === 'landing' ? 'text-[#FF3F3F]' : 'text-zinc-500 hover:text-zinc-350'
              }`}
            >
              <Home className="w-5 h-5" />
              <span className="text-[9px] uppercase tracking-wider scale-90">Home</span>
            </button>

            <button 
              id="mobile-bottom-nav-feed"
              onClick={() => setActiveTab('feed')}
              className={`flex flex-col items-center p-1 text-center font-bold cursor-pointer transition ${
                activeTab === 'feed' ? 'text-[#FF3F3F]' : 'text-zinc-500 hover:text-zinc-350'
              }`}
            >
              <LayoutGrid className="w-5 h-5" />
              <span className="text-[9px] uppercase tracking-wider scale-90">Browse</span>
            </button>
            
            <button 
              id="mobile-bottom-nav-create"
              onClick={() => setIsCreatePostOpen(true)}
              className="flex items-center justify-center w-11 h-11 bg-[#FF3F3F] text-white rounded-full -mt-6 shadow-lg shadow-[#FF3F3F]/30 hover:bg-[#E53535] active:scale-95 transition cursor-pointer"
            >
              <Plus className="w-6 h-6" />
            </button>

            <button 
              id="mobile-bottom-nav-messages"
              onClick={() => setActiveTab('messaging')}
              className={`relative flex flex-col items-center p-1 text-center font-bold cursor-pointer transition ${
                activeTab === 'messaging' ? 'text-[#FF3F3F]' : 'text-zinc-500 hover:text-zinc-300'
              }`}
            >
              <MessageSquare className="w-5 h-5" />
              <span className="text-[9px] uppercase tracking-wider scale-90">Chats</span>
              {unreadMessagesCount > 0 && (
                <span className="absolute top-1 right-2 w-2 h-2 rounded-full bg-[#FF3F3F] animate-pulse" />
              )}
            </button>

            <button 
              id="mobile-bottom-nav-login"
              onClick={() => setActiveTab('login')}
              className={`flex flex-col items-center p-1 text-center font-bold cursor-pointer transition ${
                activeTab === 'login' ? 'text-[#FF3F3F]' : 'text-zinc-500 hover:text-zinc-300'
              }`}
            >
              <UserIcon className="w-5 h-5" />
              <span className="text-[9px] uppercase tracking-wider scale-90">Sign In</span>
            </button>
          </div>
        </div>
      ) : (
        /* PHONE DEVICE FRAME SANDBOX SIMULATOR WORKSPACE */
        <div id="phone-sandbox-wrapper" className="flex-1 flex flex-col items-center justify-center p-4 bg-[#0d0d0f] overflow-y-auto min-h-screen">
          
          <div className="mb-4 text-center">
            <span className="text-xs text-zinc-400 font-bold block mb-1">
              📱 HuntInTown iOS/Android Preview Simulation
            </span>
            <button
              id="sandbox-exit-button"
              onClick={() => setIsMobileSimulated(false)}
              className="px-4 py-1.5 bg-[#1a1a1e] border border-zinc-800 text-zinc-300 hover:text-white hover:bg-zinc-800 font-black text-[10px] rounded-full transition cursor-pointer font-mono uppercase tracking-widest"
            >
              Return to Wide Web View
            </button>
          </div>

          {/* Device Shape Container */}
          <div className="w-[360px] h-[740px] bg-[#0c0c0e] border-[10px] border-zinc-800 rounded-[48px] shadow-2xl relative flex flex-col overflow-hidden ring-4 ring-zinc-800/50">
            {/* Phone Bezel Speaker Notch */}
            <div className="absolute top-0 left-1/2 -translate-x-1/2 w-32 h-5 bg-zinc-800 rounded-b-2xl z-55 flex justify-center items-center">
              <span className="w-7 h-1 bg-zinc-950 rounded-full" />
            </div>

            {/* Mock Phone Status Indicator Bar */}
            <div className="h-7 bg-zinc-900 text-zinc-450 px-6 pt-1 flex justify-between items-center text-[9px] font-mono select-none z-50">
              <span>9:41 AM</span>
              <div className="flex gap-1.5 items-center">
                <span>5G</span>
                <span className="w-5 h-2.5 bg-zinc-850 rounded-xs inline-block border border-zinc-800 relative">
                  <span className="absolute inset-y-0 left-0 bg-[#FF3F3F] w-[85%]" />
                </span>
              </div>
            </div>

            {/* Header view */}
            <div className="bg-[#121214] border-b border-[#232327] px-4 py-3 flex justify-between items-center shrink-0">
              <span className="font-black text-xs tracking-widest text-[#FF3F3F] font-display cursor-pointer" onClick={() => setActiveTab('landing')}>HuntInTown</span>
              <button 
                onClick={() => setActiveTab('login')}
                className="text-[9px] bg-red-950/40 border border-[#FF3F3F]/30 text-[#FF3F3F] px-2.5 py-1 rounded font-black hover:bg-zinc-800 uppercase font-mono tracking-wider transition cursor-pointer"
              >
                Sign In / Switch
              </button>
            </div>

            {/* Scrollable Mobile Viewport */}
            <div className="flex-1 overflow-y-auto bg-[#09090b] p-3 pb-20">
              {children}
            </div>

            {/* Mobile Bottom Tab Navigation */}
            <div className="absolute bottom-0 inset-x-0 bg-[#121214] border-t border-[#232327] flex items-center justify-around py-2 z-40 shadow-lg">
              <button 
                id="sim-mobile-nav-home"
                onClick={() => setActiveTab('landing')}
                className={`flex flex-col items-center p-1 text-center font-bold cursor-pointer transition ${
                  activeTab === 'landing' ? 'text-[#FF3F3F]' : 'text-zinc-500'
                }`}
              >
                <Home className="w-4.5 h-4.5" />
                <span className="text-[8px] uppercase tracking-wider">Home</span>
              </button>

              <button 
                id="sim-mobile-nav-feed"
                onClick={() => setActiveTab('feed')}
                className={`flex flex-col items-center p-1 text-center font-bold cursor-pointer transition ${
                  activeTab === 'feed' ? 'text-[#FF3F3F]' : 'text-zinc-500'
                }`}
              >
                <LayoutGrid className="w-4.5 h-4.5" />
                <span className="text-[8px] uppercase tracking-wider">Browse</span>
              </button>

              <button 
                id="sim-mobile-nav-create"
                onClick={() => setIsCreatePostOpen(true)}
                className="flex items-center justify-center w-10 h-10 bg-[#FF3F3F] text-white rounded-full -mt-5 shadow-lg shadow-[#FF3F3F]/30 hover:bg-[#E53535] active:scale-95 transition cursor-pointer"
              >
                <Plus className="w-5.5 h-5.5" />
              </button>

              <button 
                id="sim-mobile-nav-messages"
                onClick={() => setActiveTab('messaging')}
                className={`relative flex flex-col items-center p-1 text-center font-bold cursor-pointer transition ${
                  activeTab === 'messaging' ? 'text-[#FF3F3F]' : 'text-zinc-500'
                }`}
              >
                <MessageSquare className="w-4.5 h-4.5" />
                <span className="text-[8px] uppercase tracking-wider">Chats</span>
                {unreadMessagesCount > 0 && (
                  <span className="absolute top-1 right-2 w-1.5 h-1.5 rounded-full bg-[#FF3F3F]" />
                )}
              </button>

              <button 
                id="sim-mobile-nav-login"
                onClick={() => setActiveTab('login')}
                className={`flex flex-col items-center p-1 text-center font-bold cursor-pointer transition ${
                  activeTab === 'login' ? 'text-[#FF3F3F]' : 'text-zinc-500'
                }`}
              >
                <UserIcon className="w-4.5 h-4.5" />
                <span className="text-[8px] uppercase tracking-wider">Sign In</span>
              </button>
            </div>
          </div>
        </div>
      )}

      {/* CREATE MODAL SHEET */}
      {isCreatePostOpen && (
        <CreatePost 
          currentUser={currentUser}
          onClose={() => setIsCreatePostOpen(false)}
          onSubmit={handleCreatePost}
        />
      )}

      {/* LOGIN PROFILE CHANGER */}
      <LoginModal 
        isOpen={isLoginOpen}
        onClose={() => setIsLoginOpen(false)}
        onLogin={handleLoginSimulate}
        currentUserId={currentUser.id}
      />
    </div>
  );
}

export default function RootLayout({
  children,
}: {
  children: ReactNode;
}) {
  return (
    <html lang="en">
      <head>
        <title>HuntInTown</title>
      </head>
      <body>
        <AppContextProvider>
          <RootLayoutContent>{children}</RootLayoutContent>
        </AppContextProvider>
      </body>
    </html>
  );
}
